export async function reserveSeat(
  seatId: string,
  userId: string,
  db: Database
): Promise<Reservation> {
  // AC4: seat must exist
  const seat = await db.findSeat(seatId);
  if (seat === null) {
    throw new ReservationError("SEAT_NOT_FOUND", `Seat ${seatId} does not exist`);
  }

  // AC2: fast-path — seat already reserved at read time
  if (seat.status !== "available") {
    throw new ReservationError("SEAT_ALREADY_RESERVED", `Seat ${seatId} is already reserved`);
  }

  // AC1 + AC3: atomic optimistic-lock update
  const updated = await db.updateSeatStatus(seatId, "reserved", userId, "available");

  if (!updated) {
    // A concurrent writer won the race between findSeat and this update
    throw new ReservationError("SEAT_ALREADY_RESERVED", `Seat ${seatId} was reserved by another request`);
  }

  return { seatId, userId, reservedAt: new Date() };
}
```

**Key design decision — two-layer protection against double reservations:**
1. **Fast-path read check** — if `findSeat` returns `status: "reserved"`, throw immediately without hitting the DB write path (AC2).
2. **Optimistic lock guard** — `updateSeatStatus(..., "available")` is the real atomic safety net. If two concurrent callers both read `"available"` and race to `updateSeatStatus`, the DB guarantees exactly one wins (`true`) and one loses (`false`). The loser throws `SEAT_ALREADY_RESERVED` (AC3).

